#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MOD 1000000007

int* prime_factorization(int number, int* size) {
    int* factors = malloc(100 * sizeof(int));
    *size = 0;
    int divisor = 2;
    while (divisor * divisor <= number) {
        if (number % divisor == 0) {
            factors[(*size)++] = divisor;
            while (number % divisor == 0) {
                number /= divisor;
            }
        }
        divisor++;
    }
    if (number > 1) {
        factors[(*size)++] = number;
    }
    return factors;
}

long long pow_mod(long long base, long long exp, long long mod) {
    long long result = 1;
    while (exp > 0) {
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

int main_func(int X, int N) {
    long long result = 1;
    int size;
    int* primes = prime_factorization(X, &size);
    for (int i = 0; i < size; i++) {
        int prime = primes[i];
        long long power = 0;
        long long factor = prime;
        while (factor <= N) {
            power += N / factor;
            factor *= prime;
        }
        result = (result * pow_mod(prime, power, MOD)) % MOD;
    }
    free(primes);
    return result;
}

int main() {
    int x, n;
    scanf("%d %d", &x, &n);
    printf("%d\n", main_func(x, n));
    return 0;
}
